import json
with open('/home/halei/.openclaw/openclaw.json') as f:
    cfg = json.load(f)
def find(obj, keys, path=''):
    hits = []
    if isinstance(obj, dict):
        for k, v in obj.items():
            new_path = f'{path}.{k}' if path else k
            if k in keys:
                hits.append((new_path, v))
            hits.extend(find(v, keys, new_path))
    elif isinstance(obj, list):
        for i, v in enumerate(obj):
            hits.extend(find(v, keys, f'{path}[{i}]'))
    return hits
for k in ['allowAny', 'allowSpawn', 'spawn', 'allowList', 'allow', 'allowAgents', 'allowed', 'spawning', 'subagents']:
    hits = find(cfg, {k})
    if hits:
        print(f'键 "{k}" 出现 {len(hits)} 次:')
        for p, v in hits[:3]:
            print(f'  {p}: {json.dumps(v, ensure_ascii=False)[:200]}')
EOF

